userDefinedLinkHintCss:
div > .vimiumHintMarker {
/* linkhint boxes */
background: -webkit-gradient(linear, left top, left bottom, color-stop(0%,#FFF785),
  color-stop(100%,#FFC542));
border: 1px solid #E3BE23;
}

div > .vimiumHintMarker span {
/* linkhint text */
color: black;
font-weight: bold;
font-size: 12px;
}

div > .vimiumHintMarker > .matchingCharacter {
}

html {
  height: 100vh;
}

body {
  margin: 0px;
}

#vomnibar {
  width: calc(100% - 40px);
  margin: 20px;
  position: inherit !important;
  border: 2px solid #babbf1;
  border-radius: 0px;
  background-color: #303446;
  color: #c6d0f5;
}

#vomnibar::after{
  content: var(--tf-newtab-logo);
  display: block;
  position: absolute;
  z-index: 2147483648;
  bottom: 18%;
  white-space: pre-wrap;
  left: 50%;
  transform: translateX(-50%);
  color: #e5c890;
  font-size: 14px;
  font-weight: 600;
  font-family: var(--tf-font-family) !important;
  width: 40%;
  text-align: center;
  line-height: 16px;
}

#vomnibar-search-area {
  background-color: unset;
  display: flex;
}

#vomnibar-search-area::before {
  content: "Navigate:";
  display: flex;
  height: 20px;
  font-size: 18px;
  margin-right: 5px;
  line-height: 16px;
  white-space: nowrap;
  color: #e5c890;
}

#vomnibar input {
  background-color: unset;
  padding: 0px;
  color: #c6d0f5;
  box-shadow: unset;
  display: inline-block;
  height: 20px;
}

#vomnibar ul {
  border-top: 2px solid #babbf1;
}

#vomnibar li {
  border-bottom: 2px solid #737994;
}

#vomnibar li.selected {
  background-color: #232634;
}

#vomnibar li .top-half .source.no-insert-text {
  display: none;
}

#vomnibar li .top-half .source {
  margin: 0px;
}

#vomnibar li .bottom-half .source.no-insert-text {
  visibility: visible;
}
